#!/usr/bin/env node
let fs=require("fs"),path=require("path"),execSync=require("child_process").execSync,args=process.argv.slice(2),isDryRun=args.includes("--dry-run"),config={rootDir:path.resolve(__dirname,".."),sassDir:path.join(path.resolve(__dirname,".."),"assets/sass")};function removeSassDir(){if(fs.existsSync(config.sassDir))if(console.log("🔄 Removing Sass directory: "+config.sassDir),isDryRun)console.log("🔍 Would remove directory: "+config.sassDir);else try{"win32"===process.platform?execSync(`rmdir /s /q "${config.sassDir}"`,{stdio:"ignore"}):execSync(`rm -rf "${config.sassDir}"`,{stdio:"ignore"}),console.log("✅ Removed Sass directory: "+config.sassDir)}catch(s){console.error("❌ Failed to remove Sass directory: "+s.message)}else console.log("🔍 Sass directory does not exist: "+config.sassDir)}async function main(){console.log("🚀 Starting SCSS cleanup..."),isDryRun&&console.log("🔍 DRY RUN MODE: No files will be modified"),removeSassDir(),console.log("🎉 SCSS cleanup completed!")}main().catch(s=>{console.error("❌ Error:",s),process.exit(1)});